def test_consent_grant_missing_patient_reference(api_client, patient_auth_token):
    payload = {
        "resourceType": "Consent",
        "status": "active",
        "scope": {"coding": [{"code": "patient-privacy"}]},
        "category": [{"coding": [{"code": "59284-0"}]}],
        "provision": {"type": "permit"}
    }
    headers = {"Authorization": f"Bearer {patient_auth_token}"}
    resp = api_client.post("/Consent", json=payload, headers=headers)
    assert resp.status_code == 422
    body = resp.json()
    assert body.get("resourceType") == "OperationOutcome"
    issues = body.get("issue", [])
    assert any("patient" in str(i.get("diagnostics", "")).lower() for i in issues)

def test_revoked_consent_enforced_at_sla_boundary(
    api_client, patient_auth_token, accessor_auth_token,
    create_active_consent, advance_time
):
    consent_id = create_active_consent(patient_id="test-patient-001")
    patch_body = [{"op": "replace", "path": "/status", "value": "inactive"}]
    ph = {"Authorization": f"Bearer {patient_auth_token}"}
    revoke_resp = api_client.patch(
        f"/Consent/{consent_id}", json=patch_body,
        headers={**ph, "Content-Type": "application/json-patch+json"}
    )
    assert revoke_resp.status_code == 200
    assert revoke_resp.json().get("status") == "inactive"
    advance_time(minutes=15)
    ah = {"Authorization": f"Bearer {accessor_auth_token}"}
    data_resp = api_client.get("/Patient/test-patient-001/$everything", headers=ah)
    assert data_resp.status_code == 403

def test_consent_access_denied_without_permission(
    api_client, non_patient_token
):
    payload = {
        "resourceType": "Consent",
        "status": "active",
        "scope": {"coding": [{"code": "patient-privacy"}]},
        "category": [{"coding": [{"code": "59284-0"}]}],
        "patient": {"reference": "Patient/test-patient-004"},
        "provision": {"type": "permit"}
    }
    no_auth_resp = api_client.post("/Consent", json=payload)
    assert no_auth_resp.status_code == 401
    wrong_role_resp = api_client.post(
        "/Consent", json=payload,
        headers={"Authorization": f"Bearer {non_patient_token}"}
    )
    assert wrong_role_resp.status_code == 403
